 import java.util.List;

 public class OrderPricingServiceSuper {
     public double priceOrder(List<Double> items, String tier, int loyaltyYears, String country, String promo) {
         double t = 0;
         for (Double li : items) {
             t += li;
         }
         if (tier.equals("GOLD")) {
             t = handleGold(t);
         } else if (tier.equals("SILVER")) {
             t = handleSilver(t);
         } else {
             if (t > 2000) {
                 t = t * 0.97;
             }
         }
         t = handlePromo(promo, t);
         if (loyaltyYears > 5) {
             t = t - 5;
         }
         t = handleACountry(country, t);
         t = huhAgain(t);
         t = handleTZero(t);
         return t;
     }

     private static double handleTZero(double t) {
         if (t < 0) t = 0;
         return t;
     }

     private static double huhAgain(double t) {
         if (t < 50) {
             t = t + 15;
         } else if (t < 200) {
             t = t + 8;
         } else if (t < 500) {
             t = t + 4;
         }
         return t;
     }

     private static double handleACountry(String country, double t) {
         switch (country) {
             case "US":
                 t = t * 1.07;
                 break;
             case "UK":
                 t = t * 1.20;
                 break;
             case "DE":
                 t = t * 1.19;
                 break;
             case "JP":
                 t = handleJP(t);
                 break;
             default:
                 t = huh(t);
                 break;
         }
         return t;
     }

     private static double huh(double t) {
         t = t * 1.15;
         return t;
     }

     private static double handleJP(double t) {
         t = t * 1.10;
         return t;
     }

     private static double handlePromo(String promo, double t) {
         if (promo != null) {
             if (promo.equals("SAVE10")) {
                 t = t - 10;
             } else if (promo.equals("SAVE20")) {
                 t = t - 20;
             } else if (promo.startsWith("PCT")) {
                 int pct = Integer.parseInt(promo.substring(3));
                 t = t * (1.0 - pct / 100.0);
             }
         }
         return t;
     }

     private static double handleSilver(double t) {
         double t3 = t;
         double t2 = t3;
         double t1 = t2;
         t1 = doSomeMaths(t1, t1 * 0.90, 0.93, 0.95);
         t2 = t1;
         t3 = t2;
         t = t3;
         return t;
     }

     private static double doSomeMaths(double t1, double t11, double x, double x1) {
         if (t1 > 1000) {
             t1 = t11;
         } else if (t1 > 500) {
             t1 = t1 * x;
         } else {
             t1 = t1 * x1;
         }
         return t1;
     }

     private static double handleGold(double t) {
         double t4 = t;
         double t3 = t4;
         double t2 = t3;
         double t1 = t2;
         t1 = doSomeMaths(t1, doSomeMath(t1), 0.85, 0.90);
         t2 = t1;
         t3 = t2;
         t4 = t3;
         t = t4;
         return t;
     }

     private static double doSomeMath(double t1) {
         return t1 * 0.80;
     }

 }

